+    setCodexAppServerClientFactoryForTests(factory: CodexAppServerClientFactory): void {
+      setFactory(factory);
+    },
+    resetCodexAppServerClientFactoryForTests(): void {
+      setFactory(defaultCodexAppServerClientFactory);
+    },
+  } as const;
+}

